// Time:  O(nlogn)
// Space: O(n)

class Solution {
public:
    int minCostToSupplyWater(int n, vector<int>& wells, vector<vector<int>>& pipes) {
        vector<tuple<int, int, int>> nodes;
        for (int i = 0; i < wells.size(); ++i) {
            nodes.emplace_back(wells[i], 0, i + 1);
        }
        for (int i = 0; i < pipes.size(); ++i) {
            nodes.emplace_back(pipes[i][2], pipes[i][0], pipes[i][1]);
        }
        sort(nodes.begin(), nodes.end());
        int result = 0;
        UnionFind union_find(n + 1);
        for (const auto& [c, x, y] : nodes) {
            if (!union_find.union_set(x, y)) {
                continue;
            }
            result += c;
            if (union_find.count() == 1) {
                break;
            }
        }
        return result;
    }

private:
    class UnionFind {
    public:
        UnionFind(const int n) : set_(n), count_(n) {
            iota(set_.begin(), set_.end(), 0);
        }

        int find_set(const int x) {
           if (set_[x] != x) {
               set_[x] = find_set(set_[x]);  // Path compression.
           }
           return set_[x];
        }

        bool union_set(const int x, const int y) {
            int x_root = find_set(x), y_root = find_set(y);
            if (x_root == y_root) {
                return false;
            }
            set_[min(x_root, y_root)] = max(x_root, y_root);
            --count_;
            return true;
        }

        int count() const {
            return count_;
        }

    private:
        vector<int> set_;
        int count_;
    };
};

# Time:  O(nlogn)
# Space: O(n)

class UnionFind(object):
    def __init__(self, n):
        self.set = range(n)
        self.count = n

    def find_set(self, x):
        if self.set[x] != x:
            self.set[x] = self.find_set(self.set[x])  # path compression.
        return self.set[x]

    def union_set(self, x, y):
        x_root, y_root = map(self.find_set, (x, y))
        if x_root == y_root:
            return False
        self.set[max(x_root, y_root)] = min(x_root, y_root)
        self.count -= 1
        return True


class Solution(object):
    def minCostToSupplyWater(self, n, wells, pipes):
        """
        :type n: int
        :type wells: List[int]
        :type pipes: List[List[int]]
        :rtype: int
        """
        w = [[c, 0, i] for i, c in enumerate(wells, 1)]
        p = [[c, i, j] for i, j, c in pipes]
        result = 0
        union_find = UnionFind(n+1)
        for c, x, y in sorted(w+p):
            if not union_find.union_set(x, y):
                continue
            result += c
            if union_find.count == 1:
                break
        return result
